(4774, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'About the risk of endotracheal intubation', '["The aortic arch also may be used to estimate tube location", "If the ETT is too high, there is a risk of either inadvertent extubation or hypopharyngeal intubation,", "If the ETT is too low, selective intubation of the right mainstem bronchus may occur, hyperinflation of the right lung, and possible pneumothorax.", "The balloon cuff should fill and dilate the trachea."]'::jsonb, 3, NULL, 'Pre-Council', '🎓', true),
(4775, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'Central venous catheters (CVCs)', '["CVCs are used frequently in the ICU patient for venous access, monitoring central venous pressure, and haemodialysis.", "The subclavian, internal jugular, and femoral veins are the sites of venous access used most commonly;", "Smaller-calibre central catheters can also be peripherally inserted via antecubital veins.", "CVCs inserted via a thoracic vein are not visible on the chest radiograph"]'::jsonb, 3, NULL, 'Pre-Council', '🎓', true),
(4776, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'About central venous catheters select the wrong answer', '["Appropriate catheter position must be verified radiographically", "Malposition has been described in up to 80% of CVCs.", "Positioning of the catheter tip within the right atrium is common and may result in cardiac perforation and tamponade.", "Placement into the right ventricle may result in arrhythmias secondary to irritation of the endocardium or interventricular septum"]'::jsonb, 1, NULL, 'Pre-Council', '🎓', true),
(4777, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'About misplacement of central venous catheters', '["A misplaced CVC can result in inaccurate venous pressure readings as well as venous thrombosis or venous wall perforation.", "The most common location for a misplaced catheter entering the subclavian vein is the ipsilateral internal jugular vein.", "More frequently, thoracic CVCs may enter the azygous, internal mammary, superior intercostal.", "Looping, knotting, and kinking of the catheter may also occur"]'::jsonb, 2, NULL, 'Pre-Council', '🎓', true),
(4778, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'About pulmonary artery catheterization all are correct except', '["The pulmonary artery catheter (PAC) plays an important role in the hemodynamic monitoring of the critically ill patient.", "The catheter is inserted via the subclavian or internal jugular vein and its tip should lie within the right or left ventricle.", "The catheter tip should remain within 2 cm of the hilum.", "Complications such as pneumothorax, vascular injury, infection, and knotting, may occur"]'::jsonb, 1, NULL, 'Pre-Council', '🎓', true),
(4779, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'About cardiac pacemaker', '["Cardiac pacemakers can be inserted by trans venous only", "Most often the trans venous approach is used", "The right internal jugular and the left subclavian veins are often preferred", "When viewed on a chest radiograph, the pacemaker lead should terminate in the right ventricular apex"]'::jsonb, 0, NULL, 'Pre-Council', '🎓', true),
(4780, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'What is the definition of hypothermia?', '["A body core temperature above 35.0 oC (95.0 oF) in humans", "A body core temperature below 35.0 oC (95.0 oF) in humans", "A body core temperature below 37.0 oC (99.5 oF) in humans", "A body core temperature below 32.0 oC (90.0 oF) in humans"]'::jsonb, 1, NULL, 'Pre-Council', '🎓', true),
(4781, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'What are the symptoms of moderate hypothermia?', '["Shivering and mental confusion", "No shivering and increased confusion", "Hallucinations and paradoxical undressing", "No obvious vital signs"]'::jsonb, 0, NULL, 'Pre-Council', '🎓', true),
(4782, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'What are the recommended treatment measures for mild hypothermia?', '["Heating blankets and warmed intravenous fluids", "Extracorporeal membrane oxygenation (ECMO)", "Warm drinks, warm clothing, and physical activity", "Cardiopulmonary resuscitation (CPR)"]'::jsonb, 2, NULL, 'Pre-Council', '🎓', true),
(4783, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'What is hyperthermia?', '["An increase in body temperature caused by external factors", "A decrease in body temperature caused by internal factors", "An increase in body temperature caused by bacterial or viral infection", "A decrease in body temperature caused by bacterial or viral infection"]'::jsonb, 0, NULL, 'Pre-Council', '🎓', true),
(4784, 'Pre-Council Exam 3', 'Pre-Council Exam 3 (uploaded past-paper set)', 'What triggers the elevation of core temperature during fever?', '["Oral antibiotics", "Bacterial or viral infection", "Preoptic region of the anterior hypothalamus", "Endotoxins"]'::jsonb, 1, NULL, 'Pre-Council', '🎓', true),
